      {/* Status fullscreen viewer */}
      {viewingStatus && (() => {
        const st = viewingStatus.status;
        const isOwn = viewingStatus.username === currentUser?.username;
        return (
          <div className="anim-fadeIn" style={{ position:'fixed', inset:0, background:'#000', display:'flex', flexDirection:'column', zIndex:2000 }}
            onClick={() => setShowStatusMenu(false)}>
            {/* Progress bar */}
            <div style={{ position:'absolute', top:0, left:0, right:0, padding:'12px 16px 8px', zIndex:10 }}>
              <div style={{ height:3, borderRadius:2, background:'rgba(255,255,255,0.25)', overflow:'hidden' }}>
                <div className="status-progress-fill" style={{ height:'100%', background:'#fff', borderRadius:2 }} />
              </div>
            </div>
            {/* Header */}
            <div style={{ position:'absolute', top:28, left:0, right:0, padding:'10px 16px', display:'flex', alignItems:'center', justifyContent:'space-between', zIndex:10 }}>
              <div style={{ display:'flex', alignItems:'center', gap:10 }}>
                <div style={{ width:38, height:38, borderRadius:'50%', background:'linear-gradient(135deg,#e8748a,#c9a96e)', display:'flex', alignItems:'center', justifyContent:'center', fontSize:15, fontWeight:700, color:'#fff', border:'2px solid rgba(255,255,255,0.3)' }}>
                  {viewingStatus.username[0].toUpperCase()}
                </div>
                <div style={{ color:'#fff', fontSize:14, fontWeight:600 }}>
                  {isOwn ? 'My Status' : viewingStatus.username}
                </div>
              </div>
              <button onClick={() => setViewingStatus(null)} style={{ background:'rgba(255,255,255,0.1)', border:'none', color:'#fff', fontSize:18, cursor:'pointer', borderRadius:'50%', width:36, height:36, display:'flex', alignItems:'center', justifyContent:'center' }}>✕</button>
            </div>
            {/* Content */}
            <div className="anim-scaleIn" style={{ flex:1, display:'flex', alignItems:'center', justifyContent:'center', padding:'80px 20px' }}>
              {st.type==='text' && <div style={{ fontSize:26, color:'#fff', fontWeight:700, lineHeight:1.5, textAlign:'center' }}>{st.content}</div>}
              {st.type==='image' && <img src={st.fileUrl} alt="status" style={{ maxWidth:'100%', maxHeight:'70vh', borderRadius:12, objectFit:'contain' }} />}
              {st.type==='video' && <video src={st.fileUrl} controls autoPlay style={{ maxWidth:'100%', maxHeight:'70vh', borderRadius:12 }} />}
              {st.type==='audio' && <div style={{ textAlign:'center' }}><div style={{ fontSize:64, marginBottom:20 }}>🎵</div><audio src={st.fileUrl} controls autoPlay style={{ width:'100%' }} /></div>}
            </div>
            {/* Bottom bar */}
            <div style={{ position:'absolute', bottom:0, left:0, right:0, zIndex:10, padding:'16px 20px 32px', background:'linear-gradient(to top, rgba(0,0,0,0.9), transparent)' }}>
              <div style={{ display:'flex', alignItems:'flex-end', justifyContent:'space-between' }}>
                {/* Time info — always visible */}
                <div style={{ display:'flex', flexDirection:'column', gap:4 }}>
                  <span style={{ color:'rgba(255,255,255,0.6)', fontSize:12 }}>📅 {new Date(st.createdAt).toLocaleString([], { month:'short', day:'numeric', hour:'2-digit', minute:'2-digit' })}</span>
                  <span style={{ color:'rgba(255,200,80,0.9)', fontSize:12 }}>⏳ {(() => { const ms = new Date(st.createdAt).getTime() + 86400000 - Date.now(); if(ms<=0) return 'Expired'; const h=Math.floor(ms/3600000); const m=Math.floor((ms%3600000)/60000); return h>0?`Expires in ${h}h ${m}m`:`Expires in ${m}m`; })()}</span>
                  {/* Views — only for status owner */}
                  {isOwn && <span style={{ color:'rgba(255,255,255,0.5)', fontSize:12 }}>👁️ {st.views?.length || 0} view{st.views?.length !== 1 ? 's' : ''}{st.views?.length > 0 ? ` · ${st.views.slice(0,3).join(', ')}${st.views.length>3?'...':''}` : ''}</span>}
                </div>
                {/* 3-dot delete — only for status owner */}
                {isOwn && (
                  <div style={{ position:'relative' }} onClick={e => e.stopPropagation()}>
                    <button
                      onClick={() => setShowStatusMenu(p => !p)}
                      style={{ width:42, height:42, borderRadius:'50%', background:'rgba(255,255,255,0.15)', border:'1px solid rgba(255,255,255,0.25)', color:'#fff', fontSize:22, cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center' }}
                    >⋮</button>
                    {showStatusMenu && (
                      <div className="anim-fadeDown" style={{ position:'absolute', right:0, bottom:50, background:'#2e1820', border:'1px solid #4e2830', borderRadius:12, minWidth:160, boxShadow:'0 12px 32px rgba(0,0,0,0.7)', overflow:'hidden', zIndex:20 }}>
                        <button
                          onClick={async () => {
                            await authFetch(`/status/${st._id}`, { method:'DELETE' });
                            setViewingStatus(null);
                            setShowStatusMenu(false);
                            const res = await authFetch('/statuses');
                            const data = await res.json();
                            setStatuses(Array.isArray(data) ? data : []);
                          }}
                          style={{ width:'100%', padding:'13px 16px', background:'none', border:'none', color:'#f87171', fontSize:13, cursor:'pointer', textAlign:'left', display:'flex', alignItems:'center', gap:8, fontWeight:600 }}
                        >🗑️ Delete Status</button>
                      </div>
                    )}
                  </div>
                )}
              </div>
            </div>
          </div>
        );
      })()}

      {/* Search overlay */}
      {tab==='search' && (
        <div className="anim-fadeIn" style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.75)', zIndex:500, display:'flex', alignItems:'flex-start', justifyContent:'center', paddingTop:80 }}
          onClick={() => { setTab('chats'); setSearchQ(''); setSearchResults([]); }}>
          <div className="anim-fadeUp glass" style={{ borderRadius:16, width: isMobile ? '92vw' : 420, maxHeight:'70vh', overflow:'hidden', display:'flex', flexDirection:'column' }}
            onClick={e => e.stopPropagation()}>
            <div style={{ padding:'14px 16px', borderBottom:'1px solid #3d2028' }}>
              <input
                className="input-glow"
                style={{ width:'100%', padding:'10px 14px', background:'#221218', border:'1px solid #3d2028', borderRadius:10, color:'#e2e8f0', fontSize:14, outline:'none', boxSizing:'border-box' }}
                placeholder="🔍 Search by username..." value={searchQ} onChange={e => handleSearch(e.target.value)} autoFocus
              />
            </div>
            <div style={{ overflowY:'auto', flex:1 }}>
              {searchQ && searchResults.length===0 && <div style={{ padding:'30px 16px', textAlign:'center', color:'#334155', fontSize:13 }}>No users found</div>}
              {searchResults.map(u => (
                <div key={u._id} className="sidebar-item" style={{ display:'flex', alignItems:'center', gap:10, padding:'10px 14px', cursor:'pointer' }}>
                  <Avatar name={u.username} src={u.profilePic} />
                  <div style={{ flex:1 }}>
                    <div style={{ fontSize:14, fontWeight:500, color:'#cbd5e1' }}>{u.username}</div>
                    <div style={{ fontSize:11, color:'#475569', marginTop:2 }}>{friends.includes(u.username) ? '✅ Friends' : 'Send a request'}</div>
                  </div>
                  {!friends.includes(u.username) && (
                    <button
                      onClick={() => { if (!sentRequests.includes(u.username)) sendRequest(u.username); }}
                      style={{ padding:'5px 14px', background: sentRequests.includes(u.username) ? '#1e293b' : 'linear-gradient(90deg,#e8748a,#c9a96e)', border:'none', borderRadius:8, color: sentRequests.includes(u.username) ? '#475569' : '#fff', fontSize:12, cursor: sentRequests.includes(u.username) ? 'default' : 'pointer', fontWeight:600, flexShrink:0 }}>
                      {sentRequests.includes(u.username) ? 'Sent ✓' : 'Add +'}
                    </button>
                  )}
                </div>
              ))}
              {!searchQ && <div style={{ padding:'30px 16px', textAlign:'center', color:'#334155', fontSize:13 }}>Type a username to search</div>}
            </div>
          </div>
        </div>
      )}

      {/* ── SIDEBAR ── */}
      <div className="anim-slideLeft" style={{ width: isMobile ? '100vw' : 300, minWidth: isMobile ? '100vw' : 300, height:'100vh', background:'#221218', borderRight:'1px solid #2e1820', display: isMobile && activeContact ? 'none' : 'flex', flexDirection:'column', position: isMobile ? 'fixed' : 'relative', top:0, left:0, zIndex:10 }}>

        {/* Sidebar header */}
        <div style={{ padding: isMobile ? '14px 16px' : '20px 18px 14px', borderBottom:'1px solid #2e1820', paddingTop: isMobile ? 'max(14px,env(safe-area-inset-top))' : '20px' }}>
          <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center' }}>
            <div style={{ display:'flex', alignItems:'center', gap:8 }}>
              <ShinyHeart size={22} />
              <span className="grad-text" style={{ fontSize:20, fontWeight:800, letterSpacing:0.5 }}>Aeshunona</span>
            </div>
            <div style={{ display:'flex', gap:4 }}>
              <button onClick={() => setTab('search')} style={{ background:'none', border:'none', fontSize:18, cursor:'pointer', padding:'6px', borderRadius:8, color:'#475569', transition:'color 0.2s' }} title="Search">🔍</button>
              <button onClick={() => setShowSettings(true)} style={{ background:'none', border:'none', fontSize:18, cursor:'pointer', padding:'6px', borderRadius:8, color:'#475569', transition:'color 0.2s' }} title="Settings">⚙️</button>
            </div>
          </div>
          {/* Current user row */}
          <div style={{ display:'flex', alignItems:'center', gap:10, marginTop:12, padding:'8px 10px', background:'#221218', borderRadius:10, border:'1px solid #2e1820' }}>
            <div style={{ position:'relative' }}>
              <Avatar name={currentUser?.username} src={currentUser?.profilePic} size={32} />
              <span style={{ position:'absolute', bottom:0, right:0, width:9, height:9, borderRadius:'50%', background:'#22c55e', border:'2px solid #221218' }} />
            </div>
            <div style={{ flex:1, minWidth:0 }}>
              <div style={{ fontSize:13, fontWeight:600, color:'#e2e8f0', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{currentUser?.username}</div>
              <div style={{ fontSize:11, color:'#22c55e' }}>● Online</div>
            </div>
          </div>
        </div>

        {/* Tabs */}
        <div style={{ display:'flex', padding:'10px 12px', gap:6, borderBottom:'1px solid #2e1820' }}>
          {[['chats','💬','Chats'],['status','📸','Status'],['requests','🔔','Requests']].map(([key, icon, label]) => (
            <button
              key={key}
              className="tab-btn"
              onClick={() => { setTab(key); localStorage.setItem('chat_tab', key); if (key==='status') loadStatuses(); }}
              style={{ flex:1, padding:'8px 4px', background: tab===key ? 'linear-gradient(135deg,#e8748a,#c9a96e)' : '#221218', border:'1px solid '+(tab===key ? 'transparent' : '#3d2028'), borderRadius:9, color: tab===key ? '#fff' : '#475569', fontSize:11, fontWeight:600, cursor:'pointer', position:'relative' }}
            >
              <span style={{ fontSize:14 }}>{icon}</span>
              <span style={{ display:'block', marginTop:1 }}>{label}</span>
              {key==='requests' && requests.length>0 && (
                <span className="anim-popIn" style={{ position:'absolute', top:-4, right:-4, background:'#ef4444', color:'#fff', fontSize:9, fontWeight:700, borderRadius:10, padding:'1px 5px', minWidth:16, textAlign:'center' }}>{requests.length}</span>
              )}
            </button>
          ))}
        </div>

        {/* List area */}
        <div style={{ flex:1, overflowY:'auto' }}>

          {/* Chats tab */}
          {tab==='chats' && (
            friends.length===0
              ? (
                <div style={{ padding:'40px 20px', textAlign:'center', color:'#334155' }}>
                  <div className="anim-float" style={{ fontSize:40, marginBottom:12 }}>👥</div>
                  <div style={{ fontSize:14, fontWeight:600, marginBottom:6 }}>No friends yet</div>
                  <div style={{ fontSize:12 }}>Search users to add friends!</div>
                </div>
              )
              : friends.map(f => (
                <div
                  key={f}
                  className="sidebar-item"
                  onClick={() => openChat(f)}
                  style={{ display:'flex', alignItems:'center', gap:10, padding:'11px 14px', cursor:'pointer', background: activeContact===f ? 'rgba(232,116,138,0.1)' : 'transparent', borderLeft: activeContact===f ? '3px solid #e8748a' : '3px solid transparent', transition:'all 0.15s' }}
                >
                  <div style={{ position:'relative', flexShrink:0 }}>
                    <Avatar name={f} src={friendDetails[f]?.profilePic} size={40} />
                    {onlineFriends.includes(f) && (
                      <span style={{ position:'absolute', bottom:1, right:1, width:10, height:10, borderRadius:'50%', background:'#22c55e', border:'2px solid #221218' }} />
                    )}
                  </div>
                  <div style={{ flex:1, minWidth:0 }}>
                    <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center' }}>
                      <div style={{ fontSize:14, fontWeight:600, color:'#e2e8f0', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{f}</div>
                      {chats[f]?.length > 0 && <span style={{ fontSize:10, color:'#334155', flexShrink:0 }}>{chats[f][chats[f].length-1].time}</span>}
                    </div>
                    <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginTop:2 }}>
                      <div style={{ fontSize:11, color: unread[f]>0 ? '#f5c0c8' : '#475569', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap', maxWidth:160 }}>
                        {typingUsers[f]
                          ? <span style={{ color:'#e8748a', fontStyle:'italic' }}>typing...</span>
                          : chats[f]?.length > 0
                            ? (chats[f][chats[f].length-1].fileType==='image' ? '📷 Photo'
                              : chats[f][chats[f].length-1].fileType==='video' ? '🎬 Video'
                              : chats[f][chats[f].length-1].fileType==='audio' ? '🎵 Audio'
                              : chats[f][chats[f].length-1].fileType==='file' ? '📎 File'
                              : chats[f][chats[f].length-1].text || '')
                            : onlineFriends.includes(f) ? '● Online' : 'Offline'}
                      </div>
                      {unread[f] > 0 && (
                        <span className="anim-popIn" style={{ background:'linear-gradient(135deg,#e8748a,#c9a96e)', color:'#fff', fontSize:10, fontWeight:700, borderRadius:10, padding:'2px 7px', flexShrink:0 }}>{unread[f]}</span>
                      )}
                    </div>
                  </div>
                </div>
              ))
          )}

          {/* Status tab */}
          {tab==='status' && (
            <>
              <div style={{ padding:'12px 14px', borderBottom:'1px solid #2e1820' }}>
                <div style={{ fontSize:11, color:'#475569', fontWeight:700, marginBottom:8, textTransform:'uppercase', letterSpacing:1 }}>Post Status</div>
                <textarea
                  className="input-glow"
                  style={{ width:'100%', padding:'9px 12px', background:'#221218', border:'1px solid #3d2028', borderRadius:10, color:'#e2e8f0', fontSize:13, outline:'none', resize:'none', fontFamily:'Inter,sans-serif', boxSizing:'border-box', marginBottom:8 }}
                  rows={2} placeholder="Write a status..." value={statusText} onChange={e => setStatusText(e.target.value)}
                />
                <div style={{ display:'flex', gap:6, flexWrap:'wrap' }}>
                  {statusText.trim() && (
                    <button onClick={() => postStatus('text')} className="btn-primary" style={{ padding:'6px 14px', borderRadius:8, fontSize:12 }}>
                      {statusUploading ? 'Posting...' : '✏️ Post'}
                    </button>
                  )}
                  <input ref={statusFileRef} type="file" style={{ display:'none' }} onChange={e => { const f=e.target.files[0]; if(!f) return; const t=f.type.startsWith('image')?'image':f.type.startsWith('video')?'video':'audio'; postStatus(t,f); e.target.value=''; }} />
                  {[{icon:'🖼️',label:'Photo',accept:'image/*'},{icon:'🎬',label:'Video',accept:'video/*'},{icon:'🎵',label:'Audio',accept:'audio/*'}].map(({icon,label,accept}) => (
                    <button key={label} onClick={() => { statusFileRef.current.accept=accept; statusFileRef.current.click(); }}
                      style={{ padding:'6px 10px', background:'#221218', border:'1px solid #3d2028', borderRadius:8, color:'#94a3b8', fontSize:12, cursor:'pointer', transition:'border-color 0.2s' }}>
                      {icon}
                    </button>
                  ))}
                </div>
              </div>
              <div style={{ flex:1, overflowY:'auto' }}>
                {statuses.length===0
                  ? <div style={{ padding:'30px 16px', textAlign:'center', color:'#334155', fontSize:13 }}>No statuses yet</div>
                  : statuses.map(u => (
                    <div key={u.username} style={{ padding:'10px 14px', borderBottom:'1px solid #2e1820' }}>
                      <div style={{ fontSize:11, color:'#475569', fontWeight:600, marginBottom:6 }}>
                        {u.username===currentUser?.username ? '👤 My Status' : u.username}
                      </div>
                      <div style={{ display:'flex', gap:8, flexWrap:'wrap' }}>
                        {u.statuses.map((st,i) => (
                          <div key={i} onClick={() => {
                            setViewingStatus({ username:u.username, status:st });
                            if (u.username!==currentUser?.username && st._id) {
                              fetch(`${API}/status/${u.username}/${st._id}/view`, { method:'POST', headers:{ Authorization:`Bearer ${token}` } })
                                .then(r=>r.json()).then(data => {
                                  setStatuses(prev => prev.map(user => user.username===u.username ? { ...user, statuses: user.statuses.map(s => s._id===st._id ? {...s, views:data.views} : s) } : user));
                                });
                            }
                          }}
                            style={{ width:56, height:56, borderRadius:10, background:'#221218', border:'2px solid #e8748a', cursor:'pointer', overflow:'hidden', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0, transition:'transform 0.15s', animation:'statusRing 2s ease infinite' }}>
                            {st.type==='text' && <div style={{ fontSize:9, color:'#fde8ec', padding:3, textAlign:'center', overflow:'hidden', lineHeight:1.3 }}>{st.content?.slice(0,20)}</div>}
                            {st.type==='image' && <img src={st.fileUrl} alt="" style={{ width:'100%', height:'100%', objectFit:'cover' }} />}
                            {st.type==='video' && <div style={{ fontSize:18 }}>🎬</div>}
                            {st.type==='audio' && <div style={{ fontSize:18 }}>🎵</div>}
                          </div>
                        ))}
                      </div>
                    </div>
                  ))
                }
              </div>
            </>
          )}

          {/* Requests tab */}
          {tab==='requests' && (
            requests.length===0
              ? (
                <div style={{ padding:'40px 20px', textAlign:'center', color:'#334155' }}>
                  <div className="anim-float" style={{ fontSize:36, marginBottom:10 }}>🔔</div>
                  <div style={{ fontSize:13 }}>No pending requests</div>
                </div>
              )
              : requests.map(r => (
                <div key={r} className="anim-fadeUp sidebar-item" style={{ display:'flex', alignItems:'center', gap:10, padding:'12px 14px', borderBottom:'1px solid #2e1820' }}>
                  <Avatar name={r} size={40} />
                  <div style={{ flex:1 }}>
                    <div style={{ fontSize:14, fontWeight:600, color:'#e2e8f0', marginBottom:6 }}>{r}</div>
                    <div style={{ display:'flex', gap:6 }}>
                      <button onClick={() => acceptRequest(r)} style={{ padding:'5px 12px', background:'rgba(34,197,94,0.15)', border:'1px solid rgba(34,197,94,0.3)', borderRadius:7, color:'#4ade80', fontSize:11, cursor:'pointer', fontWeight:600 }}>✓ Accept</button>
                      <button onClick={() => rejectRequest(r)} style={{ padding:'5px 12px', background:'rgba(239,68,68,0.1)', border:'1px solid rgba(239,68,68,0.2)', borderRadius:7, color:'#f87171', fontSize:11, cursor:'pointer', fontWeight:600 }}>✕ Reject</button>
                    </div>
                  </div>
                </div>
              ))
          )}
        </div>

        {/* Logout */}
        <button
          onClick={handleLogout}
          style={{ margin:'12px', padding:'11px', background:'rgba(239,68,68,0.08)', border:'1px solid rgba(239,68,68,0.15)', borderRadius:11, color:'#f87171', cursor:'pointer', fontSize:13, fontWeight:600, transition:'background 0.2s' }}
        >
          🚪 Sign Out
        </button>
      </div>


      {/* ── CHAT AREA ── */}
      <div style={{ flex:1, minWidth:0, width: isMobile ? '100vw' : 'auto', height:'100vh', display: isMobile && !activeContact ? 'none' : 'flex', flexDirection:'column', background:'#1a0e14', overflow:'hidden', position: isMobile ? 'fixed' : 'relative', top:0, left:0, right:0, bottom:0 }}>

        {!activeContact ? (
          <div className="anim-fadeIn" style={{ flex:1, display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', color:'#334155', gap:12 }}>
            <div className="anim-float"><ShinyHeart size={64} /></div>
            <div className="grad-text" style={{ fontSize:22, fontWeight:800 }}>Aeshunona</div>
            <div style={{ fontSize:15, fontWeight:600, color:'#334155' }}>Select a friend to start chatting</div>
            <div style={{ fontSize:13, color:'#1e293b' }}>Search users → Add friends → Chat!</div>
          </div>
        ) : (
          <>
            {/* Chat header */}
            <div style={{ padding: isMobile ? '10px 12px' : '14px 20px', background:'#221218', borderBottom:'1px solid #2e1820', display:'flex', alignItems:'center', gap: isMobile ? 8 : 12, flexShrink:0, paddingTop: isMobile ? 'max(10px,env(safe-area-inset-top))' : '14px' }}>
              {isMobile && (
                <button onClick={() => setActiveContact(null)} style={{ background:'none', border:'none', color:'#f5c0c8', fontSize:22, cursor:'pointer', padding:'0 4px', flexShrink:0 }}>←</button>
              )}
              <div style={{ position:'relative', flexShrink:0 }}>
                <Avatar name={activeContact} src={friendDetails[activeContact]?.profilePic} size={40} />
                {onlineFriends.includes(activeContact) && (
                  <span style={{ position:'absolute', bottom:1, right:1, width:10, height:10, borderRadius:'50%', background:'#22c55e', border:'2px solid #221218' }} />
                )}
              </div>
              <div style={{ flex:1 }}>
                <div style={{ fontWeight:700, fontSize: isMobile ? 14 : 15, color:'#e2e8f0' }}>{activeContact}</div>
                <div style={{ fontSize:12 }}>
                  {typingUsers[activeContact]
                    ? <span style={{ color:'#e8748a', fontStyle:'italic' }}>typing...</span>
                    : onlineFriends.includes(activeContact)
                      ? <span style={{ color:'#22c55e' }}><OnlineDot />Online • AI-powered</span>
                      : <span style={{ color:'#475569' }}>{lastSeenStr(activeContact) || 'Offline'}</span>
                  }
                </div>
              </div>

              {/* Message search toggle */}
              <button onClick={() => setShowMsgSearch(p => !p)} style={{ background:'none', border:'none', color:'#475569', fontSize:18, cursor:'pointer', padding:'4px 8px' }} title="Search messages">🔍</button>

              {/* 3-dot menu */}
              <div style={{ position:'relative', flexShrink:0 }}>
                <button onClick={() => setShowContactMenu(p => !p)} style={{ background:'none', border:'none', color:'#475569', fontSize:22, cursor:'pointer', padding:'4px 8px' }}>⋮</button>
                {showContactMenu && (
                  <div className="anim-fadeDown" style={{ position:'absolute', right:0, top:40, background:'#2e1820', border:'1px solid #3d2028', borderRadius:12, minWidth:170, zIndex:100, boxShadow:'0 12px 32px rgba(0,0,0,0.5)', overflow:'hidden' }}
                    onClick={() => setShowContactMenu(false)}>
                    <button onClick={() => unfriend(activeContact)} style={{ width:'100%', padding:'12px 16px', background:'none', border:'none', color:'#f87171', fontSize:13, cursor:'pointer', textAlign:'left', borderBottom:'1px solid #3d2028' }}>👤 Unfriend</button>
                    <button onClick={() => blockUser(activeContact)} style={{ width:'100%', padding:'12px 16px', background:'none', border:'none', color:'#fbbf24', fontSize:13, cursor:'pointer', textAlign:'left' }}>🚫 Block</button>
                  </div>
                )}
              </div>
            </div>

            {/* Message search bar */}
            {showMsgSearch && (
              <div className="anim-fadeDown" style={{ padding:'8px 16px', background:'#221218', borderBottom:'1px solid #2e1820', display:'flex', gap:8, alignItems:'center' }}>
                <input
                  className="input-glow"
                  style={{ flex:1, padding:'8px 12px', background:'#221218', border:'1px solid #3d2028', borderRadius:9, color:'#e2e8f0', fontSize:13, outline:'none' }}
                  placeholder="Search messages..."
                  value={msgSearch}
                  onChange={e => setMsgSearch(e.target.value)}
                  autoFocus
                />
                <button onClick={() => { setShowMsgSearch(false); setMsgSearch(''); }} style={{ background:'none', border:'none', color:'#475569', cursor:'pointer', fontSize:18 }}>✕</button>
              </div>
            )}

            {/* Messages */}
            <div className="chat-scroll" style={{ flex:1, minHeight:0, overflowY:'auto', padding: isMobile ? '12px' : '20px', display:'flex', flexDirection:'column', gap:10, WebkitOverflowScrolling:'touch' }}>
              {activeMessages.length===0
                ? (
                  <div className="anim-fadeIn" style={{ flex:1, display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', color:'#334155', gap:8, paddingTop:60 }}>
                    <div className="anim-float" style={{ fontSize:44 }}>👋</div>
                    <div style={{ fontSize:15, fontWeight:600 }}>No messages yet</div>
                    <div style={{ fontSize:13 }}>Say hi to {activeContact}!</div>
                  </div>
                )
                : activeMessages.map((c, i) => {
                    const mine = c.sender === currentUser?.username;
                    return (
                      <div key={i} className="msg-row" style={{ display:'flex', justifyContent: mine ? 'flex-end' : 'flex-start', alignItems:'flex-end', gap:8, width:'100%' }}
                        onClick={() => { setShowEmojiFor(null); setMsgContextMenu(null); }}>
                        {!mine && <Avatar name={activeContact} src={friendDetails[activeContact]?.profilePic} size={30} />}
                        <div style={{ maxWidth:'70%', display:'inline-flex', flexDirection:'column' }}>
                          {/* Reply preview */}
                          {c.replyTo && (
                            <div style={{ background:'rgba(255,255,255,0.05)', borderLeft:'3px solid #e8748a', borderRadius:'8px 8px 0 0', padding:'6px 10px', fontSize:11, color:'#94a3b8', marginBottom:2 }}>
                              <span style={{ color:'#f0a0b0', fontWeight:600 }}>{c.replyTo.sender}: </span>
                              {c.replyTo.fileType ? `📎 ${c.replyTo.fileType}` : c.replyTo.text?.slice(0,60)}
                            </div>
                          )}
                          <div style={{ position:'relative' }}>
                            <div
                              className="msg-bubble"
                              onContextMenu={e => { e.preventDefault(); setMsgContextMenu({ msgId:c._id, x:e.clientX, y:e.clientY, seenAt:c.seenAt, mine }); }}
                              style={{ display:'inline-block', padding:'10px 14px', borderRadius: mine ? '18px 18px 4px 18px' : '18px 18px 18px 4px', background: mine ? 'linear-gradient(135deg,#e8748a,#c9a96e)' : '#2e1820', border: mine ? 'none' : '1px solid #3d2028', color:'#e2e8f0', fontSize:14, lineHeight:1.6, wordBreak:'normal', overflowWrap:'break-word', whiteSpace:'pre-wrap', boxShadow: mine ? '0 4px 16px rgba(232,116,138,0.25)' : 'none' }}
                            >
                              {c.fileType==='image' && <img src={c.fileUrl} alt="img" style={{ maxWidth:'100%', borderRadius:8, display:'block', marginBottom: c.text ? 6 : 0 }} />}
                              {c.fileType==='video' && <video src={c.fileUrl} controls style={{ maxWidth:'100%', borderRadius:8, display:'block', marginBottom: c.text ? 6 : 0 }} />}
                              {c.fileType==='audio' && <audio src={c.fileUrl} controls style={{ width:'100%', marginBottom: c.text ? 6 : 0 }} />}
                              {c.fileType==='file' && <a href={c.fileUrl} target="_blank" rel="noreferrer" style={{ color:'#f5c0c8', fontSize:13, display:'block', marginBottom: c.text ? 6 : 0 }}>📎 {c.fileName}</a>}
                              {c.text && <span>{c.text}</span>}
                              {!c.text && !c.fileType && <span style={{ color:'#94a3b8', fontSize:12 }}>📎 File</span>}
                            </div>

                            {/* Action buttons */}
                            <div style={{ display:'flex', gap:4, marginTop:4, justifyContent: mine ? 'flex-end' : 'flex-start' }}>
                              <button className="emoji-btn" onClick={e => { e.stopPropagation(); setShowEmojiFor(showEmojiFor===c._id ? null : c._id); }}
                                style={{ background:'none', border:'none', fontSize:14, cursor:'pointer', opacity:0.5, padding:'2px 4px' }}>😊</button>
                              <button onClick={e => { e.stopPropagation(); setReplyingTo(c); }}
                                style={{ background:'none', border:'none', fontSize:11, cursor:'pointer', opacity:0.5, color:'#94a3b8', padding:'2px 6px' }}>↩ Reply</button>
                            </div>

                            {/* Emoji picker */}
                            {showEmojiFor===c._id && (
                              <div className="anim-popIn" onClick={e => e.stopPropagation()} style={{ position:'absolute', [mine?'right':'left']:0, bottom:44, background:'#2e1820', border:'1px solid #3d2028', borderRadius:14, padding:'8px 12px', display:'flex', gap:8, zIndex:50, boxShadow:'0 8px 24px rgba(0,0,0,0.5)' }}>
                                {['❤️','😂','😮','😢','👍','🔥'].map(emoji => (
                                  <button key={emoji} className="emoji-btn" onClick={() => reactToMsg(c._id, emoji)}
                                    style={{ background:'none', border:'none', fontSize:22, cursor:'pointer' }}>{emoji}</button>
                                ))}
                              </div>
                            )}
                          </div>

                          {/* Reactions */}
                          {c.reactions?.length > 0 && (
                            <div style={{ display:'flex', gap:4, flexWrap:'wrap', marginTop:4, justifyContent: mine ? 'flex-end' : 'flex-start' }}>
                              {Object.entries(c.reactions.reduce((acc, r) => { acc[r.emoji]=(acc[r.emoji]||0)+1; return acc; }, {})).map(([emoji, count]) => (
                                <span key={emoji} onClick={() => reactToMsg(c._id, emoji)}
                                  style={{ background:'#2e1820', border:'1px solid #3d2028', borderRadius:20, padding:'2px 8px', fontSize:12, cursor:'pointer', transition:'transform 0.1s' }}>
                                  {emoji}{count > 1 ? ` ${count}` : ''}
                                </span>
                              ))}
                            </div>
                          )}

                          {/* Meta */}
                          <div style={{ display:'flex', alignItems:'center', gap:6, marginTop:4, justifyContent: mine ? 'flex-end' : 'flex-start', flexWrap:'wrap' }}>
                            <span style={{ fontSize:10, color:'#334155' }}>{c.time}</span>
                            {mine && c.seenAt && <span style={{ fontSize:10, color:'#e8748a' }}>✓✓</span>}
                            {mine && !c.seenAt && <span style={{ fontSize:10, color:'#334155' }}>✓</span>}
                            {c.sentiment && c.text && (
                              <span style={{ background: sentimentColor(c.sentiment).bg, color: sentimentColor(c.sentiment).color, fontSize:10, padding:'2px 7px', borderRadius:20, fontWeight:600 }}>{c.sentiment}</span>
                            )}
                          </div>
                        </div>
                        {mine && <Avatar name={currentUser.username} src={currentUser.profilePic} size={30} />}
                      </div>
                    );
                  })
              }
              {/* Typing indicator */}
              {typingUsers[activeContact] && (
                <div className="anim-fadeUp" style={{ display:'flex', alignItems:'flex-end', gap:8 }}>
                  <Avatar name={activeContact} src={friendDetails[activeContact]?.profilePic} size={30} />
                  <TypingIndicator />
                </div>
              )}
              <div ref={messagesEndRef} />
            </div>

            {/* Notification banner */}
            {notification && (
              <div className="toast" style={{ margin:'0 16px 8px', padding:'10px 14px', background:'rgba(34,197,94,0.1)', border:'1px solid rgba(34,197,94,0.2)', borderRadius:12, fontSize:13, color:'#4ade80' }}>{notification}</div>
            )}
            {warning && (
              <div className="toast" style={{ margin:'0 16px 8px', padding:'10px 14px', background:'rgba(245,158,11,0.1)', border:'1px solid rgba(245,158,11,0.2)', borderRadius:12, fontSize:13, color:'#fbbf24' }}>⚠️ {warning}</div>
            )}

            {/* Context menu */}
            {msgContextMenu && (
              <div onClick={() => setMsgContextMenu(null)} style={{ position:'fixed', inset:0, zIndex:200 }}>
                <div className="anim-scaleIn" onClick={e => e.stopPropagation()} style={{ position:'fixed', top: Math.min(msgContextMenu.y, window.innerHeight-130), left: Math.min(msgContextMenu.x, window.innerWidth-200), background:'#2e1820', border:'1px solid #3d2028', borderRadius:12, padding:'6px 0', minWidth:180, boxShadow:'0 12px 32px rgba(0,0,0,0.5)', zIndex:201, overflow:'hidden' }}>
                  {msgContextMenu.mine && (
                    <div style={{ padding:'10px 16px', fontSize:13, color: msgContextMenu.seenAt ? '#4ade80' : '#64748b', borderBottom:'1px solid #3d2028' }}>
                      {msgContextMenu.seenAt ? `✅ Seen at ${new Date(msgContextMenu.seenAt).toLocaleTimeString([],{hour:'2-digit',minute:'2-digit'})}` : '🕐 Not seen yet'}
                    </div>
                  )}
                  <div style={{ padding:'10px 16px', fontSize:13, color:'#e2e8f0', cursor:'pointer' }}
                    onClick={() => { const m=activeMessages.find(m=>m._id===msgContextMenu.msgId); if(m) setReplyingTo(m); setMsgContextMenu(null); }}>
                    ↩ Reply
                  </div>
                  <div style={{ padding:'10px 16px', fontSize:13, color:'#e2e8f0', cursor:'pointer', borderTop:'1px solid #3d2028' }}
                    onClick={() => { setShowEmojiFor(msgContextMenu.msgId); setMsgContextMenu(null); }}>
                    😊 React
                  </div>
                </div>
              </div>
            )}

            {/* Smart replies */}
            {smartReplies.length > 0 && (
              <div className="anim-fadeUp" style={{ margin:'0 16px 8px', display:'flex', gap:8, flexWrap:'wrap', flexShrink:0, alignItems:'center' }}>
                <span style={{ fontSize:11, color:'#f0a0b0', fontWeight:700, flexShrink:0 }}>💡</span>
                {smartReplies.map((r, i) => (
                  <button key={i} onClick={() => send(r)}
                    style={{ background:'rgba(232,116,138,0.1)', border:'1px solid rgba(232,116,138,0.3)', color:'#fde8ec', fontSize:12, padding:'6px 14px', borderRadius:20, cursor:'pointer', fontWeight:500, whiteSpace:'nowrap', transition:'background 0.15s' }}>
                    {r}
                  </button>
                ))}
                <button onClick={() => setSmartReplies([])} style={{ background:'transparent', border:'none', color:'#475569', cursor:'pointer', fontSize:16 }}>✕</button>
              </div>
            )}

            {/* Input area */}
            <div style={{ position:'relative', padding: isMobile ? '8px 12px' : '12px 20px', background:'#221218', borderTop:'1px solid #2e1820', display:'flex', gap:8, alignItems:'flex-end', flexShrink:0, paddingBottom: isMobile ? 'max(8px,env(safe-area-inset-bottom))' : '12px' }}>
              {/* Reply preview */}
              {replyingTo && (
                <div className="anim-fadeDown" style={{ position:'absolute', bottom:'100%', left:0, right:0, background:'#221218', borderTop:'1px solid #6b2535', padding:'8px 16px', display:'flex', alignItems:'center', justifyContent:'space-between' }}>
                  <div style={{ fontSize:12, color:'#f0a0b0' }}>
                    <span style={{ fontWeight:600 }}>↩ {replyingTo.sender}: </span>
                    <span style={{ color:'#94a3b8' }}>{replyingTo.fileType ? `📎 ${replyingTo.fileType}` : replyingTo.text?.slice(0,50)}</span>
                  </div>
                  <button onClick={() => setReplyingTo(null)} style={{ background:'none', border:'none', color:'#475569', cursor:'pointer', fontSize:16 }}>✕</button>
                </div>
              )}

              <input type="file" ref={fileInputRef} style={{ display:'none' }} onChange={e => { sendFile(e.target.files[0]); e.target.value=''; }} />
              <button onClick={() => fileInputRef.current.click()} style={{ padding: isMobile ? '10px 12px' : '11px 14px', background:'#2e1820', border:'1px solid #3d2028', borderRadius:12, color:'#64748b', cursor:'pointer', fontSize:18, flexShrink:0, transition:'border-color 0.2s' }} title="Send file">
                {sendingFile ? <div style={{ width:18, height:18, border:'2px solid #334155', borderTop:'2px solid #e8748a', borderRadius:'50%', animation:'spin 0.7s linear infinite' }} /> : '📎'}
              </button>

              <textarea
                className="input-glow"
                style={{ flex:1, minWidth:0, padding: isMobile ? '10px 12px' : '11px 14px', background:'#221218', border:'1px solid #3d2028', borderRadius:12, color:'#e2e8f0', fontSize:14, outline:'none', resize:'none', fontFamily:'Inter,sans-serif', lineHeight:1.5, maxHeight:100, overflowY:'auto', width:'100%', boxSizing:'border-box', transition:'border-color 0.2s, box-shadow 0.2s' }}
                rows={1}
                value={msg}
                onChange={e => setMsg(e.target.value)}
                onKeyDown={handleKey}
                onFocus={handleFocus}
                placeholder={`Message ${activeContact}...`}
              />

              <button
                onClick={() => send()}
                className={msg.trim() ? 'btn-primary' : ''}
                style={{ padding: isMobile ? '10px 14px' : '11px 18px', background: msg.trim() ? 'linear-gradient(135deg,#e8748a,#c9a96e)' : '#2e1820', border:'1px solid '+(msg.trim() ? 'transparent' : '#3d2028'), borderRadius:12, color: msg.trim() ? '#fff' : '#475569', cursor: msg.trim() ? 'pointer' : 'default', fontWeight:700, fontSize:14, flexShrink:0, transition:'all 0.2s' }}
              >
                ➤
              </button>
            </div>
          </>
        )}
      </div>
    </div>
  );
}
